// Change this to test different companies
// Use 'batch' to run all 5 test companies at once
const testCase = 'batch';

const testCompanies = {
  waterloop: {
    company_name: 'Waterloop',
    company_url: 'https://waterloop.org',
    source: 'v9 Test',
    expected: 'Invalid entity (podcast)'
  },
  fathom: {
    company_name: 'Fathom',
    company_url: 'https://fathom.video',
    source: 'v9 Test',
    expected: 'PLG-dominant'
  },
  brainbase: {
    company_name: 'Brainbase',
    company_url: 'https://brainbase.com',
    source: 'v9 Test',
    expected: 'Acquired by PE'
  },
  capboard: {
    company_name: 'Capboard',
    company_url: 'https://capboard.io',
    source: 'v9 Test',
    expected: 'Non-US primary market'
  },
  vivun: {
    company_name: 'Vivun',
    company_url: 'https://vivun.com',
    source: 'v9 Test',
    expected: 'Stale or Pre-sales'
  },
  pika: {
    company_name: 'Pika Energy',
    company_url: 'https://pika-energy.com',
    source: 'v9 Test',
    expected: 'Acquired'
  },
  batch: [
    { company_name: 'Nomi Health', company_url: 'https://nomihealth.com', source: 'v9.1 Test', expected: 'Should DQ: direct care services' },
    { company_name: 'Vesta Healthcare', company_url: 'https://vestahealthcare.com', source: 'v9.1 Test', expected: 'Should DQ: virtual care services' },
    { company_name: 'Nava Benefits', company_url: 'https://navabenefits.com', source: 'v9.1 Test', expected: 'Should DQ: benefits brokerage' },
    { company_name: 'PatientPing', company_url: 'https://bamboohealth.com', source: 'v9.1 Test', expected: 'Should DQ: PE-backed (Clearlake)' }
  ]
};

// For batch mode, return array of items
if (testCase === 'batch') {
  return testCompanies.batch.map(c => ({ json: c }));
}
// Single test case - still return as array for runOnceForAllItems mode
return [{ json: testCompanies[testCase] }];
